// Affinity GBA Runtime — Mode 7 floor with orbit camera + OAM sprites
// Built with devkitARM + libtonc

#include <tonc.h>
#include <string.h>

// Fix IWRAM_CODE: tonc's definition lacks target("arm"), so IWRAM functions
// compile as Thumb (2x slower). Override to force ARM mode in IWRAM.
#undef IWRAM_CODE
#define IWRAM_CODE __attribute__((section(".iwram"), long_call, target("arm")))

// ---------------------------------------------------------------------------
// Map data — generated by editor, or fallback checkerboard
// ---------------------------------------------------------------------------

#include "mapdata.h"

// ---------------------------------------------------------------------------
// Mode 7 state
// ---------------------------------------------------------------------------

// Camera (16.8 fixed-point for position, angle in brads)
static FIXED cam_x;
static FIXED cam_z;
static FIXED cam_h;        // height above floor
static u16   cam_angle;    // brad angle
static FIXED cam_fov;      // focal distance D

// Precomputed sin/cos for current angle
static FIXED g_cosf, g_sinf;

// EWRAM texture cache — ROM reads are 4-8 wait states per byte,
// EWRAM is 2. Copying textures here gives ~2-4x fill rate boost.
#if defined(AFN_MESH_COUNT) && AFN_MESH_COUNT > 0
#define TEX_CACHE_SIZE 4096
extern u8 tex_iwram[TEX_CACHE_SIZE]; // IWRAM buffer (defined in tex_iwram.c)
#define tex_cache tex_iwram
static u8* tex_cache_ptrs[AFN_MESH_COUNT];

// ARM assembly textured scanline inner loop (tex_scanline.s, runs in IWRAM)
extern void tex_scanline_asm(u16* rp, int pairCount, int su, int sv,
                             int du2, int dv2, const u8* tex,
                             int texMask, int texShift, int palBase);
#endif

// Debug profiling counters
static int dbg_tex_tris;    // textured triangles this frame
static int dbg_tex_spans;   // textured scanlines this frame
static int dbg_tex_pixels;  // textured pixel pairs this frame
static int dbg_vcount;      // VCOUNT delta (scanlines consumed by render)

// Tiny 4x5 digit font for debug overlay (digits 0-9, packed as 4-bit rows)
static const u32 dbg_font[10] = {
    0x69996, // 0
    0x26227, // 1
    0x69127, // 2  (top-down: 0110, 1001, 0001, 0010, 0111)
    0x69196, // 3
    0x99711, // 4
    0x78196, // 5
    0x68996, // 6
    0x71122, // 7
    0x69996, // 8  (same as 0 but different middle)
    0x69716, // 9
};

// Draw a digit (0-9) at pixel position (px,py) into Mode 4 buffer using palette index ci
static void dbg_digit(u16* buf, int px, int py, int d, u8 ci)
{
    if (d < 0 || d > 9) return;
    u32 g = dbg_font[d];
    int row, col;
    for (row = 0; row < 5; row++) {
        int bits = (g >> (4 * (4 - row))) & 0xF;
        int sy = py + row;
        if (sy < 0 || sy >= 160) continue;
        u16* r = buf + sy * 120;
        for (col = 0; col < 4; col++) {
            if (bits & (8 >> col)) {
                int sx = px + col;
                if (sx < 0 || sx >= 240) continue;
                if (sx & 1)
                    r[sx >> 1] = (r[sx >> 1] & 0x00FF) | ((u16)ci << 8);
                else
                    r[sx >> 1] = (r[sx >> 1] & 0xFF00) | ci;
            }
        }
    }
}

// Draw an integer (up to 5 digits) at pixel position
static void dbg_int(u16* buf, int px, int py, int val, u8 ci)
{
    char digits[6];
    int n = 0, v = val < 0 ? -val : val;
    if (v == 0) { digits[n++] = 0; }
    else { while (v > 0 && n < 5) { digits[n++] = v % 10; v /= 10; } }
    int i;
    for (i = n - 1; i >= 0; i--)
        dbg_digit(buf, px + (n - 1 - i) * 5, py, digits[i], ci);
}

