// ---------------------------------------------------------------------------
// Floor sprites — positions in 16.8 fixed-point
// ---------------------------------------------------------------------------

#define MAX_FLOOR_SPRITES 16

typedef struct {
    FIXED x;
    FIXED y;         // height above floor (16.8)
    FIXED z;
    u16   palIdx;    // OBJ palette color index
    s16   assetIdx;  // sprite asset index (-1 = default solid tile)
    FIXED scale;     // 8.8 fixed-point scale (256 = 1x)
    u16   rotation;  // world-space facing angle (brad, 0-65535)
    u8    animEnabled; // 0 = static, 1 = animate
    u8    spriteType;  // 0=Prop, 1=Player, 2=Enemy, etc.
    s16   meshIdx;     // index into mesh data (-1 = no mesh, use OAM sprite)
} FloorSpriteGBA;

static FloorSpriteGBA g_sprites[MAX_FLOOR_SPRITES];
static int g_spriteCount = 0;

#if defined(AFN_MESH_COUNT) && AFN_MESH_COUNT > 0
static int g_page = 0;
#endif

// Sprite projection result for sorting
typedef struct {
    int screenX;
    int screenY;
    int scale;    // 8.8 fixed-point scale (256 = 1x)
    int depth;    // for sorting (larger = farther)
    int idx;      // sprite index
} SpriteProjGBA;

// ---------------------------------------------------------------------------
// Mode 7 HBlank interrupt — per-scanline affine update
// ---------------------------------------------------------------------------

static void m7_hbl(void)
{
    int vc = REG_VCOUNT;

    // Above horizon: disable BG2 so backdrop color (sky) shows
    if (vc < m7_horizon)
    {
        REG_DISPCNT &= ~DCNT_BG2;
        return;
    }
    if (vc >= SCREEN_HEIGHT)
        return;

    // Re-enable BG2 at horizon
    REG_DISPCNT |= DCNT_BG2;

    // lambda = cam_height / (scanline - horizon)
    FIXED lam = cam_h * lu_div(vc - m7_horizon) >> 12;

    FIXED lcf = lam * g_cosf >> 8;
    FIXED lsf = lam * g_sinf >> 8;

    // Affine matrix — only PA and PC matter for per-scanline Mode 7
    REG_BG2PA =  lcf >> 4;
    REG_BG2PB = 0;
    REG_BG2PC =  lsf >> 4;
    REG_BG2PD = 0;

    // Reference point
    FIXED lxr, lyr;

    lxr = 120 * (lcf >> 4);
    lyr = cam_fov * (lsf >> 4);
    REG_BG2X = cam_x - lxr + lyr;

    lxr = 120 * (lsf >> 4);
    lyr = cam_fov * (lcf >> 4);
    REG_BG2Y = cam_z - lxr - lyr;
}

// ---------------------------------------------------------------------------
// Build checkerboard tiles + tilemap
// ---------------------------------------------------------------------------

static void load_checkerboard(void)
{
    pal_bg_mem[0] = RGB15(10, 16, 24);  // backdrop = sky blue
    pal_bg_mem[1] = RGB15(4, 10, 4);
    pal_bg_mem[2] = RGB15(8, 18, 8);
    pal_bg_mem[3] = RGB15(2, 6, 2);    // void/out-of-bounds dark green

    // Tile 0 = transparent (palette 0 = backdrop/sky blue) for out-of-bounds
    memset(&tile8_mem[2][0], 0, 64);

    // Tile 1 = solid dark, Tile 2 = solid light (full 8x8 each)
    memset(&tile8_mem[2][1], 1, 64);
    memset(&tile8_mem[2][2], 2, 64);

    // Fill 64x64 map: 2x2 tile checkerboard (each checker = 2x2 tiles = 16x16 px)
    {
        u8 *map = (u8*)se_mem[28];
        int y, x;
        memset(map, 0, 64 * 64);
        for (y = 0; y < 32; y++)
            for (x = 0; x < 32; x++)
                map[y * 64 + x] = (((x / 2) + (y / 2)) & 1) ? 2 : 1;
    }
}

#ifdef AFFINITY_HAS_MAPDATA
static void load_editor_map(void)
{
    memcpy(&tile8_mem[2][0], afn_tiles, afn_tilesLen);
    memcpy(pal_bg_mem, afn_palette, afn_paletteLen);
    // Tile the 32x32 map into 64x64 (2x2 repeat) to match editor floor density
    u8 *map = (u8*)se_mem[28];
    const u8 *src = (const u8*)afn_tilemap;
    int y, x;
    for (y = 0; y < 64; y++)
        for (x = 0; x < 64; x++)
            map[y * 64 + x] = src[(y & 31) * 32 + (x & 31)];
}
#endif

// ---------------------------------------------------------------------------
// OBJ sprite setup
// ---------------------------------------------------------------------------

static void init_obj_sprites(void)
{
    int i;
    REG_DISPCNT |= DCNT_OBJ | DCNT_OBJ_1D;

#ifdef AFN_ASSET_COUNT
#if AFN_ASSET_COUNT > 0
    // Copy all asset tile data into OBJ VRAM (charblock 4)
    // In Mode 4 (bitmap), tiles 0-511 overlap the framebuffer — offset to tile 512
    {
        const u32 *src = afn_all_tiles;
#if defined(AFN_MESH_COUNT) && AFN_MESH_COUNT > 0
        u32 *dst = (u32*)&tile_mem[4][512];
#else
        u32 *dst = (u32*)tile_mem[4];
#endif
        for (i = 0; i < (int)(AFN_ALL_TILES_LEN / 4); i++)
            dst[i] = src[i];
    }

    // Load per-asset palettes into OBJ palette banks
    for (i = 0; i < AFN_ASSET_COUNT; i++)
    {
        int palBank = afn_asset_desc[i][4];
        const u16 *pal = 0;
        switch (i) {
            case 0: pal = afn_pal0; break;
#if AFN_ASSET_COUNT > 1
            case 1: pal = afn_pal1; break;
#endif
#if AFN_ASSET_COUNT > 2
            case 2: pal = afn_pal2; break;
#endif
#if AFN_ASSET_COUNT > 3
            case 3: pal = afn_pal3; break;
#endif
#if AFN_ASSET_COUNT > 4
            case 4: pal = afn_pal4; break;
#endif
#if AFN_ASSET_COUNT > 5
            case 5: pal = afn_pal5; break;
#endif
#if AFN_ASSET_COUNT > 6
            case 6: pal = afn_pal6; break;
#endif
#if AFN_ASSET_COUNT > 7
            case 7: pal = afn_pal7; break;
#endif
            default: break;
        }
        if (pal)
        {
            int c;
            for (c = 0; c < 16; c++)
                pal_obj_mem[palBank * 16 + c] = pal[c];
        }
    }

    // Init direction animation set tracking — DMA set 0 from ROM at boot
#if defined(AFN_HAS_ASSET_DIRS) && AFN_ASSET_COUNT > 0
    {
        int ai;
        for (ai = 0; ai < AFN_ASSET_COUNT; ai++)
        {
            g_active_dir_set[ai] = -1; // mark as unloaded so switch_dir_anim_set works
            g_current_anim[ai] = 0;
            g_asset_anim_enabled[ai] = 0;
        }
        g_anim_frame_counter = 0;
    }
#endif

    // Load per-asset direction palettes if present
#ifdef AFN_HAS_ASSET_DIRS
    {
        int ai;
        for (ai = 0; ai < AFN_ASSET_COUNT; ai++)
        {
            if (!afn_asset_dir_desc[ai][4]) continue; // no directions
            int adPalBank = afn_asset_dir_desc[ai][3];
            const u16 *adPal = 0;
            switch (ai) {
                case 0: adPal = afn_pal_assetdir0; break;
#if AFN_ASSET_COUNT > 1
                case 1: adPal = afn_pal_assetdir1; break;
#endif
#if AFN_ASSET_COUNT > 2
                case 2: adPal = afn_pal_assetdir2; break;
#endif
#if AFN_ASSET_COUNT > 3
                case 3: adPal = afn_pal_assetdir3; break;
#endif
                default: break;
            }
            if (adPal)
            {
                int c;
                for (c = 0; c < 16; c++)
                    pal_obj_mem[adPalBank * 16 + c] = adPal[c];
            }
        }
    }
#endif

#endif
#else
    // No assets — use fallback solid 8x8 tile
    {
        u32 *t0 = (u32*)&tile_mem[4][0];
        int k;
        for (k = 0; k < 8; k++) t0[k] = 0x11111111;
    }
    pal_obj_mem[1*16 + 1] = RGB15(31, 31, 0);
    pal_obj_mem[2*16 + 1] = RGB15(31, 8, 8);
    pal_obj_mem[3*16 + 1] = RGB15(8, 8, 31);
    pal_obj_mem[4*16 + 1] = RGB15(8, 31, 8);
    pal_obj_mem[5*16 + 1] = RGB15(31, 16, 31);
#endif

    // Minimap dot tile
    {
#ifdef AFN_MINIMAP_TILE
        u32 *dot = (u32*)&tile_mem[4][AFN_MINIMAP_TILE];
#else
        u32 *dot = (u32*)&tile_mem[4][16];
#endif
        int k;
        for (k = 0; k < 8; k++) dot[k] = 0;
        dot[0] = 0x00000011;
        dot[1] = 0x00000011;
    }

    // Minimap palette bank (bank 6)
    pal_obj_mem[6*16 + 0] = 0;
    pal_obj_mem[6*16 + 1] = RGB15(31, 31, 31);
    pal_obj_mem[6*16 + 2] = RGB15(20, 20, 20);
    pal_obj_mem[6*16 + 3] = RGB15(31, 0, 0);

    oam_init(obj_mem, 128);
}

